          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateY: arrow2Move }],
                opacity: arrow2Fade,
              },
            ]}
          >
            <Image height={41} width={30} source={arrow} />
          </Animated.View>
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateX: 30 }, { translateY: arrow3Move }],
                opacity: arrow3Fade,
              },
            ]}
          >
            <Image height={41} width={30} source={arrow} />
          </Animated.View>
        </Box>
      </Box>
      <Text align="center" mt="middle" type="subtitleLarger">
        Estamos carregando suas informações...
      </Text>
    </Container>
  );
};

export default AnimationArrowsView;

