  PropsTokensRadiusCore,
  PropsSpacesHorizontal,
  PropsSpacesVertical,
} from '../../../../styles/Models';
import { PropsTokenColorsCore } from '../../../../styles/Models/type.colors';

type FlexAlignType =
  | 'flex-start'
  | 'flex-end'
  | 'center'
  | 'stretch'
  | 'baseline';
type JustifyContentType =
  | 'flex-start'
  | 'flex-end'
  | 'center'
  | 'space-between'
  | 'space-around'
  | 'space-evenly';
type ResizeModeType = 'cover' | 'contain' | 'stretch' | 'repeat' | 'center';

export interface PropsImageBanner {
  width?: string | number;
  height?: string | number;
  mr?: number;
  borderRadiusTopLeft?: PropsTokensRadiusCore;
  borderRadiusTopRight?: PropsTokensRadiusCore;
  borderRadiusBottomLeft?: PropsTokensRadiusCore;
  borderRadiusBottomRight?: PropsTokensRadiusCore;
}

export type PropsImage = {
  width?: string | number;
  height?: string | number;
  maxWidth?: string | number;
  minWidth?: string | number;
  minHeight?: string | number;
  maxHeight?: string | number;
  mr?: PropsSpacesVertical;
  ml?: PropsSpacesVertical;
  mt?: PropsSpacesHorizontal;
  mb?: PropsSpacesHorizontal;
  resizeMode?: ResizeModeType;
  borderRadiusTopLeft?: PropsTokensRadiusCore;
  borderRadiusTopRight?: PropsTokensRadiusCore;
  borderRadiusBottomLeft?: PropsTokensRadiusCore;
  borderRadiusBottomRight?: PropsTokensRadiusCore;
  bgColor?: PropsTokenColorsCore;
  position?: 'relative' | 'absolute';
  index?: number;
};

export interface PropsImageBackground {
  width?: string | number;
  height?: string | number;
  children?: ReactNode;
  mr?: PropsSpacesVertical;
  ml?: PropsSpacesVertical;
  mt?: PropsSpacesHorizontal;
  mb?: PropsSpacesHorizontal;
  resizeMode?: ResizeModeType;
  borderRadiusTopLeft?: PropsTokensRadiusCore;
  borderRadiusTopRight?: PropsTokensRadiusCore;
  borderRadiusBottomLeft?: PropsTokensRadiusCore;
  borderRadiusBottomRight?: PropsTokensRadiusCore;
  bgColor?: PropsTokenColorsCore;
  align?: FlexAlignType;
  justify?: JustifyContentType;
  position?: 'relative' | 'absolute';
  index?: number;
  opacity?: number;
}

